// auth.ts
import NextAuth from "next-auth"
import GitHub from "next-auth/providers/github"
import { PrismaClient } from "@prisma/client"

const prisma = new PrismaClient()

// 🚨 런타임 메모리에 보안 환경변수가 제대로 적재되었는지 터미널에 강제 출력
console.log("=== NextAuth 보안 설정 적재 확인 ===");
console.log("1. GITHUB_ID:", process.env.AUTH_GITHUB_ID ? "정상 로드됨" : "❌ NULL (값 없음)");
console.log("2. GITHUB_SECRET:", process.env.AUTH_GITHUB_SECRET ? "정상 로드됨" : "❌ NULL (값 없음)");
console.log("3. AUTH_SECRET:", process.env.AUTH_SECRET ? "정상 로드됨" : "❌ NULL (값 없음)");
console.log("==================================");

export const { handlers, auth, signIn, signOut } = NextAuth({
  debug: true,
  secret: process.env.AUTH_SECRET,
  providers: [
    GitHub({
      // 환경변수를 강제로 주입하여 라이브러리의 자동 탐지 오류를 방지합니다.
      clientId: process.env.AUTH_GITHUB_ID as string,
      clientSecret: process.env.AUTH_GITHUB_SECRET as string,
    })
  ],
  callbacks: {
    async signIn({ user }) {
      if (!user.email) return false;
      try {
        await prisma.user.upsert({
          where: { email: user.email },
          update: { name: user.name, image: user.image },
          create: { email: user.email, name: user.name, image: user.image },
        });
        return true;
      } catch (error) {
        console.error("❌ DB 저장 에러:", error);
        return false;
      }
    },
  },
})